  external_id, name, description, organizer_name, address, city, state, latitude, longitude,
  start_datetime, end_datetime, event_status, visibility_status, parking_info, admission_info,
  market_type, hours_summary, website_url, extra_info, external_source, sync_metadata
)
on conflict (external_source, external_id)
where external_source is not null and external_id is not null
do update set
  name = excluded.name,
  description = excluded.description,
  organizer_name = excluded.organizer_name,
  address = excluded.address,
  city = excluded.city,
  state = excluded.state,
  latitude = excluded.latitude,
  longitude = excluded.longitude,
  start_datetime = excluded.start_datetime,
  end_datetime = excluded.end_datetime,
  event_status = excluded.event_status,
  visibility_status = excluded.visibility_status,
  parking_info = excluded.parking_info,
  admission_info = excluded.admission_info,
  market_type = excluded.market_type,
  hours_summary = excluded.hours_summary,
  website_url = excluded.website_url,
  extra_info = excluded.extra_info,
  last_synced_at = now(),
  sync_metadata = excluded.sync_metadata,
  updated_at = now();


insert into public.events
  (external_id, name, description, organizer_name, address, city, state, latitude, longitude,
   start_datetime, end_datetime, event_status, visibility_status, parking_info, admission_info,
   market_type, hours_summary, website_url, extra_info, external_source, last_synced_at, sync_metadata)
select
  v.external_id,
  v.name,
  v.description,
  v.organizer_name,
  v.address,
  v.city,
  v.state,
  v.latitude,
  v.longitude,
  v.start_datetime::timestamptz,
  v.end_datetime::timestamptz,
  v.event_status,
  v.visibility_status,
  v.parking_info,
  v.admission_info,
  v.market_type,
  v.hours_summary,
